args.sparql:
SELECT ?hometown ?label WHERE {
  ?director wdt:P166 wd:Q748006 .
  ?director p:P166 ?award .
  ?award pq:P585 ?time .
  FILTER(YEAR(?time) = 1992)
  ?movie wdt:P57 ?director ;
         wdt:P161 wd:Q173637 ;
         wdt:P161 wd:Q136209 .
  ?director wdt:P19 ?hometown .
  OPTIONAL { ?hometown rdfs:label ?label . FILTER(LANG(?label) = "en") }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" } 
}

